        std::lock_guard<std::mutex> lock(mutex_);
        callbacks_copy.reserve(listeners_.size());
        for (const auto &[id, cb] : listeners_)
        {
            callbacks_copy.push_back(cb);
        }
    }

    for (const auto &cb : callbacks_copy)
    {
        cb(old_state, new_state);
    }
}
```

