The `PrintTaskList()` function can be implemented similarly to how task states are retrieved and printed in `PrintTaskCpuUsage()`. Use `uxTaskGetSystemState()` to get a snapshot of all tasks.

```cpp
void SystemInfo::PrintTaskList()
{
    TaskStatus_t *task_status_array;
    UBaseType_t task_count;
    UBaseType_t array_size;

    // Add some extra space in case tasks are created during measurement
    array_size = uxTaskGetNumberOfTasks() + 5;
    task_status_array = (TaskStatus_t *)malloc(sizeof(TaskStatus_t) * array_size);

    if (task_status_array == NULL)
    {
        ESP_LOGE(TAG, "Failed to allocate memory for task list");
        return;
    }

    // Retrieve current task states
    task_count = uxTaskGetSystemState(task_status_array, array_size, NULL);

    if (task_count == 0)
    {
        ESP_LOGE(TAG, "Failed to retrieve task list");
        free(task_status_array);
        return;
    }

    printf("Task List:\\n");
    printf("| %-16s | %-5s | %-8s | %-8s | %-10s |\\n", "Name", "State", "Priority", "StackMin", "TaskNum");
    for (UBaseType_t i = 0; i < task_count; i++)
    {
        const char* state_str;
        switch (task_status_array[i].eCurrentState)
        {
            case eRunning:   state_str = "Running";   break;
            case eReady:     state_str = "Ready";     break;
            case eBlocked:   state_str = "Blocked";   break;
            case eSuspended: state_str = "Suspended"; break;
            case eDeleted:   state_str = "Deleted";   break;
            default:         state_str = "Unknown";   break;
        }

        printf("| %-16s | %-7s | %8lu | %8lu | %10lu |\\n",
               task_status_array[i].pcTaskName,
               state_str,
               task_status_array[i].uxCurrentPriority,
               task_status_array[i].usStackHighWaterMark,
               task_status_array[i].xTaskNumber);
    }

    free(task_status_array);
}
```

