void AudioCodec::Start()
{
    if (output_enabled_) {
        // Configure and install I2S TX channel
        i2s_chan_config_t chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_CHAN_TX, I2S_STANDARD_MODE);
        ESP_ERROR_CHECK(i2s_new_channel(&chan_cfg, &tx_handle_, NULL));

        // Configure I2S TX slot and clock
        i2s_std_config_t std_cfg = {
            .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(output_sample_rate_),
            .slot_cfg = I2S_STD_PHILIPS_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, static_cast<i2s_slot_mode_t>(output_channels_)),
            .gpio_cfg = {
                .mck_io_num = I2S_MCK_GPIO,
                .bck_io_num = I2S_BCK_GPIO,
                .ws_io_num = I2S_WS_GPIO,
                .data_out_num = I2S_DO_GPIO,
                .data_in_num = I2S_DI_GPIO
            }
        };
        ESP_ERROR_CHECK(i2s_channel_init_std_mode(tx_handle_, &std_cfg));
        ESP_ERROR_CHECK(i2s_channel_enable(tx_handle_));
    }

    if (input_enabled_) {
        // Configure and install I2S RX channel
        i2s_chan_config_t chan_cfg = I2S_CHANNEL_DEFAULT_CONFIG(I2S_CHAN_RX, I2S_STANDARD_MODE);
        ESP_ERROR_CHECK(i2s_new_channel(&chan_cfg, NULL, &rx_handle_));

        // Configure I2S RX slot and clock
        i2s_std_config_t std_cfg = {
            .clk_cfg = I2S_STD_CLK_DEFAULT_CONFIG(input_sample_rate_),
            .slot_cfg = I2S_STD_PHILIPS_SLOT_DEFAULT_CONFIG(I2S_DATA_BIT_WIDTH_16BIT, static_cast<i2s_slot_mode_t>(input_channels_)),
            .gpio_cfg = {
                .mck_io_num = I2S_MCK_GPIO,
                .bck_io_num = I2S_BCK_GPIO,
                .ws_io_num = I2S_WS_GPIO,
                .data_out_num = I2S_DO_GPIO,
                .data_in_num = I2S_DI_GPIO
            }
        };
        ESP_ERROR_CHECK(i2s_channel_init_std_mode(rx_handle_, &std_cfg));
        ESP_ERROR_CHECK(i2s_channel_enable(rx_handle_));
    }
}
